parameters.jsCode:
// Traer outputs de los nodos previos
const setData = $('SET Normalize Input').first().json;
const smbRows = $('SUPABASE Get SocialMediaBios').all().map(i => i.json).filter(x => x && x.id);
const insights = $('SUPABASE Get Top Insights').all().map(i => i.json).filter(x => x && x.id);
const hooks = $('SUPABASE Get Top Hooks').all().map(i => i.json).filter(x => x && x.id);
const profileRow = $('SUPABASE Get Brand Profile').first().json;

// Competitor videos from social media pipeline (optional)
let competitorVideos = [];
try {
  competitorVideos = $('Fetch Competitor Videos').all().map(i => i.json).filter(x => x && x.link);
  competitorVideos.sort((a, b) => (b.views || 0) - (a.views || 0));
  competitorVideos = competitorVideos.slice(0, 10);
} catch(e) { competitorVideos = []; }

// Extract competitor hooks from analysis + concepts
const competitorHooks = [];
competitorVideos.forEach(v => {
  if (v.analysis) {
    const visualMatch = v.analysis.match(/\*\*VISUAL[^:]*:\*\*\s*(.+?)(?:\n|$)/i);
    if (visualMatch && visualMatch[1].length > 10) {
      competitorHooks.push({ text: visualMatch[1].trim(), source: v.competitor_name || v.creator, platform: v.platform || 'instagram', views: v.views || 0, type: 'visual_hook' });
    }
    const spokenMatch = v.analysis.match(/\*\*SPOKEN[^:]*:\*\*[^"]*"([^"]{15,150})"/);
    if (spokenMatch) {
      competitorHooks.push({ text: spokenMatch[1].trim(), source: v.competitor_name || v.creator, platform: v.platform || 'instagram', views: v.views || 0, type: 'spoken_hook' });
    }
  }
  if (v.new_concepts) {
    const spokenMatches = [...String(v.new_concepts).matchAll(/\*\*SPOKEN[^:]*:\*\*[^"]*"([^"]{15,150})"/g)];
    spokenMatches.slice(0, 2).forEach(m => {
      competitorHooks.push({ text: m[1].trim(), source: v.competitor_name || v.creator, platform: v.platform || 'instagram', views: v.views || 0, type: 'claude_concept' });
    });
  }
});
competitorHooks.sort((a, b) => (b.views || 0) - (a.views || 0));
const topCompetitorHooks = competitorHooks.slice(0, 8);

const channelFilter = setData.channel_filter || null;
const personaFilter = setData.persona_filter || null;
const verticals     = Array.isArray(setData.verticals) ? setData.verticals : [];

// ── SocialMediaBios per-channel ──
let smbRow = null;
if (channelFilter && smbRows.length) {
  smbRow = smbRows.find(r => (r.channel || '').toLowerCase() === channelFilter.toLowerCase()) || smbRows[0];
} else {
  smbRow = smbRows[0] || null;
}
if (!smbRow) {
  throw new Error('No hay análisis de SocialMediaBios para esta marca. Coré WF-02 sobre Instagram/TikTok primero.');
}

let analysis = smbRow.analysis_json || {};
if (typeof analysis === 'string') {
  try { analysis = JSON.parse(analysis); } catch (e) { analysis = {}; }
}
const voiceRules  = analysis.voiceRules || { always: [], never: [] };
const tone        = analysis.tone || null;
const toneSummary = analysis.toneSummary || '';
const topPosts    = Array.isArray(analysis.topPosts) ? analysis.topPosts : [];

// ── Brand profile (identity, mission, services, tone_by_channel, content_samples) ──
let profile = profileRow?.data_json || {};
if (typeof profile === 'string') {
  try { profile = JSON.parse(profile); } catch (e) { profile = {}; }
}
const identity = profile.identity || {};
const services = Array.isArray(profile.services) ? profile.services : [];
const toneByChannel = Array.isArray(profile.tone_by_channel) ? profile.tone_by_channel : [];
const contentSamples = Array.isArray(profile.content_samples) ? profile.content_samples : [];
const personasArr = Array.isArray(profile.personas) ? profile.personas : [];
const competitorsArr = Array.isArray(profile.competitors) ? profile.competitors.slice(0, 8).map(c => ({ name: c.name, positioning: c.positioning, tier: c.tier })) : [];

const targetChannel = channelFilter || smbRow.channel || 'LinkedIn';
const toneForChannel = toneByChannel.find(t => (t.channel || '').toLowerCase() === targetChannel.toLowerCase()) || null;
const samplesForChannel = contentSamples.filter(s => (s.channel || '').toLowerCase() === targetChannel.toLowerCase()).slice(0, 3);

// ── Insights ──
let chosenInsight = null;
let sourceInsightIds = [];
if (insights.length) {
  const insightsForChannel = insights.filter(i => i.channel === targetChannel);
  chosenInsight = insightsForChannel[0] || insights[0];
  sourceInsightIds = [chosenInsight.id];
} else if (topPosts.length) {
  const best = topPosts[0];
  chosenInsight = {
    id: null,
    title: `Replicar el ángulo que más engagement tuvo en ${targetChannel}`,
    insight_type: 'own_top_post_pattern',
    score: best.score || best.engagementRate || 0,
    payload_json: {
      reference_post: (best.text || best.snippet || '').slice(0, 240),
      why_it_worked: best.whyItWorked || null,
      target_persona_guess: null,
    },
    channel: targetChannel,
  };
} else {
  chosenInsight = {
    id: null,
    title: `Generic brief for ${targetChannel}`,
    insight_type: 'fallback',
    score: 0,
    payload_json: {},
    channel: targetChannel,
  };
}

let chosenHook = null;
if (hooks.length) {
  const hooksForChannel = hooks.filter(h => h.channel === targetChannel);
  chosenHook = hooksForChannel[0] || hooks[0];
} else {
  chosenHook = { id: null, hook_text: null, framework: 'auto', channel: targetChannel };
}

const personaGuess =
  personaFilter ||
  (chosenInsight.payload_json && chosenInsight.payload_json.target_persona_guess) ||
  'Primary buyer';

const ownTopPosts = topPosts.slice(0, 3).map(p => ({
  format: p.format,
  text: (p.text || p.snippet || '').slice(0, 200),
  why_it_worked: p.whyItWorked || null,
  engagement_rate: p.engagementRate || null,
}));

return [{
  json: {
    brand_id: setData.brand_id,
    hook_id: chosenHook.id,
    source_insight_ids: sourceInsightIds,
    channel: targetChannel,
    persona: personaGuess,
    verticals,
    model_input: {
      identity: {
        company_name: identity.company_name || 'SWL Consulting',
        tagline: identity.tagline || '',
        mission: identity.mission || '',
        industry: identity.industry || '',
        website: identity.website_url || '',
      },
      services,
      personas: personasArr.slice(0, 6),
      competitors_short: competitorsArr,
      brand_voice_rules: voiceRules,
      tone_dimensions: tone,
      tone_summary: toneSummary,
      tone_by_channel: toneForChannel,
      own_top_posts: ownTopPosts,
      content_samples_for_channel: samplesForChannel,
      top_insight: {
        title: chosenInsight.title,
        insight_type: chosenInsight.insight_type,
        score: chosenInsight.score,
        payload: chosenInsight.payload_json,
      },
      selected_hook: {
        text: chosenHook.hook_text,
        framework: chosenHook.framework,
        channel: chosenHook.channel,
      },
      competitor_hooks: topCompetitorHooks,
      target_channel: targetChannel,
      target_persona: personaGuess,
      verticals,
    },
  },
}];

textOptions.schema:
{
  "type": "object",
  "additionalProperties": false,
  "required": [
    "topic",
    "hook",
    "target_persona",
    "pain_points",
    "desired_outcomes",
    "opening",
    "body",
    "cta"
  ],
  "properties": {
    "topic": {
      "type": "string",
      "description": "Tema principal del post, en una frase corta"
    },
    "hook": {
      "type": "string",
      "description": "Primera línea que captura atención. Founder POV, frase directa."
    },
    "target_persona": {
      "type": "string",
      "description": "Persona específica a la que le hablamos (ej: VP Engineering)"
    },
    "pain_points": {
      "type": "array",
      "items": { "type": "string" },
      "description": "Lista de dolores concretos del persona, 3-5 ítems"
    },
    "desired_outcomes": {
      "type": "array",
      "items": { "type": "string" },
      "description": "Resultados que el persona quiere conseguir, 3-5 ítems"
    },
    "opening": {
      "type": "string",
      "description": "Primera oración del post tras el hook. Incluye una métrica concreta si es posible."
    },
    "body": {
      "type": "array",
      "items": { "type": "string" },
      "description": "Párrafos centrales del post (2-4 párrafos)"
    },
    "cta": {
      "type": "string",
      "description": "Una sola oración con el próximo paso concreto. Siempre se llama 'cta'."
    }
  }
}

