const aiOutput = $input.first().json;

let brief;
try {
  // OpenAI con json_schema responde el contenido en .text directamente como objeto,
  // o como string que hay que parsear.
  const content = aiOutput.output?.[0]?.content?.[0]?.text
               ?? aiOutput.choices?.[0]?.message?.content
               ?? aiOutput.text
               ?? aiOutput;

  brief = (typeof content === 'string') ? JSON.parse(content) : content;
  // Si vino envuelto en {brief: {...}}, desenvolvelo
  if (brief.brief) brief = brief.brief;

} catch (e) {
  throw new Error('No se pudo parsear la respuesta de OpenAI: ' + e.message);
}

const ctx = $('CODE Build Brief Context').first().json;

return [{
  json: {
    brand_id: ctx.brand_id,
    topic: brief.topic,
    channel: ctx.channel,
    persona: brief.target_persona,
    goal: brief.cta,
    hook_id: ctx.hook_id,
    source_insight_ids: ctx.source_insight_ids,
    brief_json: brief,
    status: 'ready',
  },
}];

